import{_ as a,o as r,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const f=JSON.parse('{"title":"Additional Link Configuration","description":"","frontmatter":{"title":"Additional Link Configuration","slug":"additional-link-configuration"},"headers":[],"relativePath":"account-hub/additional-link-configuration.md","filePath":"account-hub/additional-link-configuration.md"}'),i={name:"account-hub/additional-link-configuration.md"};function n(l,e,d,s,h,c){return r(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="desktop-app-default-link-behavior" tabindex="-1">Desktop app default link behavior <a class="header-anchor" href="#desktop-app-default-link-behavior" aria-label="Permalink to &quot;Desktop app default link behavior&quot;">​</a></h2><ol><li>In the Branch Dashboard, navigate to <a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>App Settings</strong></a> → <strong>General</strong> tab → <strong>Desktop Redirects</strong> section.</li><li>For <strong>Default Desktop</strong>, select either:<br> a. Branch-hosted QR Code Landing Page or<br> b. Custom Landing Page</li><li>For <strong>Mac Desktop</strong>, enter:<br> a. Mac URI Scheme<br> b. Mac App Store URL</li><li>For <strong>Windows Desktop</strong>, enter:<br> a. Windows URI Scheme<br> b. Windows Store URL<br> c. Windows Package Family Name</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>If the app is not installed when the link is clicked, we will fall back to the Desktop or Default URL, in that order.</p></div><h2 id="advanced-mobile-redirects" tabindex="-1">Advanced mobile redirects <a class="header-anchor" href="#advanced-mobile-redirects" aria-label="Permalink to &quot;Advanced mobile redirects&quot;">​</a></h2><p>The settings in this section allow you to specify different destination URLs or app store listings for users accessing your content on various mobile devices and platforms like Amazon Fire, iPad, Android tablets, and even within WeChat. This ensures users are directed to the most appropriate app or web experience for their device.</p><h3 id="amazon-fire-default-link-behavior" tabindex="-1">Amazon Fire default link behavior <a class="header-anchor" href="#amazon-fire-default-link-behavior" aria-label="Permalink to &quot;Amazon Fire default link behavior&quot;">​</a></h3><ol><li>In the Branch Dashboard, navigate to <a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>App Settings</strong></a> → <strong>General</strong> tab → <strong>Advanced Mobile Redirects</strong> section.</li><li>In the <strong>Fire Redirects</strong> section, enter your Amazon Fire URL. If you have a different package for the Amazon Store than the Plat Store on Fire devices, specify the Amazon Fire URL using the <code>p=package</code> <a href="https://developer.amazon.com/docs/reports-promo/deeplink-to-the-amazon-client.html" target="_blank" rel="noreferrer">parameter</a>.</li></ol><h3 id="ipad-redirect-link-behavior" tabindex="-1">iPad redirect link behavior <a class="header-anchor" href="#ipad-redirect-link-behavior" aria-label="Permalink to &quot;iPad redirect link behavior&quot;">​</a></h3><ol><li>On the <a href="https://dashboard.branch.io/configuration" target="_blank" rel="noreferrer">Configuration</a> page, in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">General</a> tab, navigate to the <strong>Advanced Mobile Redirects</strong> section.</li><li>In the <strong>iPad Redirects</strong> section, if you have a different App Store ID for your iPad app or would prefer to fall back to a different URL on iPad tablets, please specify either URL here.</li></ol><h3 id="android-tablet-redirect-link-behavior" tabindex="-1">Android tablet redirect link behavior <a class="header-anchor" href="#android-tablet-redirect-link-behavior" aria-label="Permalink to &quot;Android tablet redirect link behavior&quot;">​</a></h3><ol><li>On the <a href="https://dashboard.branch.io/configuration" target="_blank" rel="noreferrer">Configuration</a> page, in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">General</a> tab, navigate to the <strong>Advanced Mobile Redirects</strong> section.</li><li>In the <strong>Android Redirects</strong> section, if you have a different Play Store package for your tablet apps or would prefer to fall back to a different URL on Android tablets, please specify either URL here.</li></ol><h3 id="wechat-redirect-link-behavior" tabindex="-1">WeChat redirect link behavior <a class="header-anchor" href="#wechat-redirect-link-behavior" aria-label="Permalink to &quot;WeChat redirect link behavior&quot;">​</a></h3><ol><li>On the <a href="https://dashboard.branch.io/configuration" target="_blank" rel="noreferrer">Configuration</a> page, in the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">General</a> tab, navigate to the <strong>Advanced Mobile Redirects</strong> section.</li><li>Because WeChat does not support deep linking out of the app on iOS or Android, if you choose to fall back to a custom URL, you can enter it here.</li></ol>',13)])])}const p=a(i,[["render",n]]);export{f as __pageData,p as default};
